#!/usr/bin/env node
import fs from 'node:fs';
import path from 'node:path';

const root = path.resolve(new URL('..', import.meta.url).pathname);
const output = 'assets/css/bbai-dashboard-page.bundle.css';
const files = [
  'assets/css/components/job-widget.css',
  'assets/css/unified.css',
  'assets/css/system/bbai-admin-foundation-tokens.css',
  'assets/css/modern.bundle.css',
  'assets/css/bbai-admin.css',
  'assets/css/features/dashboard/status-card-refresh.css',
  'assets/css/features/dashboard/command-hero-host.css',
  'assets/css/features/dashboard/filter-group.css',
  'assets/css/features/dashboard/queue-workflow.css',
  'assets/css/features/dashboard/funnel-hero.css',
  'assets/css/features/dashboard/usage-strip.css',
  'assets/css/features/dashboard/dashboard-retention-strip.css',
  'assets/css/features/pricing/upgrade-modal-refresh.css',
  'assets/css/features/dashboard/saas-consistency.css',
  'assets/css/features/dashboard/product-banner.css',
  'assets/css/features/dashboard/page-hero.css',
  'assets/css/features/dashboard/admin-ui-components.css',
  'assets/css/features/dashboard/micro-motion.css',
  'assets/css/system/bbai-card-rhythm.css',
  'assets/css/features/dashboard/bbai-section-header.css',
  'assets/css/features/dashboard/dashboard-header.css',
  'assets/css/system/bbai-admin-controls.css',
  'assets/css/system/bbai-admin-interactions.css',
  'assets/css/system/bbai-admin-product-states.css',
  'assets/css/system/bbai-admin-surfaces.css',
  'assets/css/system/bbai-admin-design-system.css',
  'assets/css/system/bbai-admin-semantic-status.css',
  'assets/css/system/bbai-admin-table-workspace.css',
  'assets/css/system/bbai-admin-page-adoption.css',
  'assets/css/system/bbai-admin-surface-taxonomy.css',
  'assets/css/system/bbai-admin-library-workspace-polish.css',
  'assets/css/system/bbai-admin-button-system.css',
  'assets/css/bbai-modal.css',
  'assets/css/system/bbai-bulk-progress-refresh.css',
  'assets/css/features/automation/phase17-assistant.css',
  'assets/css/bbai-tooltips.css',
  'assets/css/features/dashboard/logged-in-state.css',
  'assets/css/features/dashboard/dashboard-composition.css',
];

const parts = [
  '/*',
  ' * BeepBeep AI dashboard page CSS bundle.',
  ' * Generated by scripts/build-dashboard-css-bundle.mjs.',
  ' * Do not edit this file directly; edit source CSS files instead.',
  ' */',
  '',
];

for (const relative of files) {
  const absolute = path.join(root, relative);
  if (!fs.existsSync(absolute)) {
    throw new Error(`Missing CSS source: ${relative}`);
  }
  const css = fs.readFileSync(absolute, 'utf8').trim();
  parts.push(`/* Source: ${relative} */`);
  parts.push(css);
  parts.push('');
}

fs.writeFileSync(path.join(root, output), `${parts.join('\n')}\n`);
console.log(`Wrote ${output} from ${files.length} files.`);
